package liuren

// biFaCatalog 《大六壬毕法赋》100 条（凌福之著，郭御青注）。
//
// 数据来源：夜空的博客整理本（m.zhifou123.com/?id=63）。
// 每条 Title 取首字四至七字，Text 直接复用 Title 作原文摘句，Note 为释义。
var biFaCatalog = []BiFaEntry{
	{Number: 1, Title: "前后引从升迁吉", Text: "前后引从升迁吉", Note: "如初传居干或支前为引，末传居干或支後为从；引从天干格利升官，引从地支格必迁居。如庚辰日干上丑，壬子日干上辰。"},
	{Number: 2, Title: "首尾相见始终宜", Text: "首尾相见始终宜", Note: "谓干上有旬尾、支上有旬首，名周而复始格，或一旬周遍格；占事不脱、所谋皆成、赴试宜代工，不宜占释放事。"},
	{Number: 3, Title: "帘幕贵人高甲第", Text: "帘幕贵人高甲第", Note: "帘幕官者，乃昼占是夜贵、夜占是昼贵，占科考专视此神，临年命日干上必中；庶人得林下官扶持，有官人得之主休官。"},
	{Number: 4, Title: "催官使者赴官期", Text: "催官使者赴官期", Note: "凡占上官赴任，见日鬼乘白虎、加临日干或年命上，名催官使者；若值空亡又是虚信。鬼曜逢虎号催官也。"},
	{Number: 5, Title: "六阳数足须公用", Text: "六阳数足须公用", Note: "六阳格，谓支干、四课、三传，皆居六阳之位是也。凡占利公干不利私谋。"},
	{Number: 6, Title: "六阴相继尽昏迷", Text: "六阴相继尽昏迷", Note: "六阴格，谓课传皆居六阴之位是也。凡占利私谋不利公事。"},
	{Number: 7, Title: "旺禄临身徒妄作", Text: "旺禄临身徒妄作", Note: "谓日之禄神、又作日之旺神，临于干上者，切不可含此而别谋动作。如乙卯日干上卯，若舍此旺禄而就初传之财、中末之生殊不知皆是旬空也。"},
	{Number: 8, Title: "权摄不正禄临支", Text: "权摄不正禄临支", Note: "谓日干禄神，加临支辰上者，凡占不自尊大，受屈折于他人。如占差迁，主权摄不正，或遥授职禄，或正宜受宅上之禄。如甲子日寅加子。"},
	{Number: 9, Title: "避难逃生须弃旧", Text: "避难逃生须弃旧", Note: "三传皆无益，或旬空、或日鬼、或脱气，惟干上尚逢吉星，即避三传之难，而受干支上之生。如丁卯日干上亥，乙卯日干上酉之类。"},
	{Number: 10, Title: "朽木难雕别作为", Text: "朽木难雕别作为", Note: "谓斫轮课中，卯为空亡者，故名朽木不可雕也。凡占宜改科易业，别作营生。如庚戌日卯加申，辛亥日卯加辛。"},
	{Number: 11, Title: "众鬼虽彰全不畏", Text: "众鬼虽彰全不畏", Note: "例如壬辰日戌加未，三传戌丑辰，皆是日鬼，诚为凶也；殊不知干上先有寅木，可以敌其三传之土，制鬼不能为害，且发用坐空，鬼力轻，终不能为祸也。"},
	{Number: 12, Title: "虽忧狐假虎威仪", Text: "虽忧狐假虎威仪", Note: "如丁未日干上子，其丁火实畏子水所克，反依赖支属土，能制其子水不致来伤丁干也。以丁火喻狐，未土喻虎，故名为狐假虎威仪也。又辛亥日干上亥。"},
	{Number: 13, Title: "鬼贼当时无畏忌", Text: "鬼贼当时无畏忌", Note: "如春占三传皆木、或三合木局，而为日鬼，诚可畏也；殊不知木至春令而荣旺，既贪荣盛而无意克土，土尚无畏，防至夏秋，其祸乃发。如戊子日干上午。"},
	{Number: 14, Title: "传财太旺反财亏", Text: "传财太旺反财亏", Note: "三传皆作日之财，其昼夜天将亦财之类，又值财生旺之月，求财反无财也。缘财自贪生旺，不能与我作财，须待身旺之月、财气稍衰，方可取之。"},
	{Number: 15, Title: "脱上逢脱防虚诈", Text: "脱上逢脱防虚诈", Note: "谓日干生其上神、上神又生天将，故名脱上脱。凡占尽被脱耗、虚诈不实之象也。如六庚日干上子， 夜将上乘青龙。"},
	{Number: 16, Title: "空上乘空事莫追", Text: "空上乘空事莫追", Note: "谓日干上见旬空乘天空者，凡占指空划空、全无实象，如甲申日干上未，昼占。另有脱空格，谓干上有脱乘天空，凡占皆无中生有，不足信也，如辛卯日干上子，昼占。"},
	{Number: 17, Title: "进茹空亡宜退步", Text: "进茹空亡宜退步", Note: "於进连茹课中，三传皆逢空落空，即应退守，视支干上是否可以依托，以全身远害。如壬子日干上子，向前三传寅卯辰皆空，退步于支干上主子与丑合反有所得。"},
	{Number: 18, Title: "踏脚空亡进用宜", Text: "踏脚空亡进用宜", Note: "此谓退连茹课中，三传皆遇空亡，故名踏脚空亡；既退后遇空，则宜进而不宜退也。如戊申日干上辰，三传逆茹、生日，岂宜皆空，寻死格也。"},
	{Number: 19, Title: "胎财生气妻怀孕", Text: "胎财生气妻怀孕", Note: "谓日干之胎神作日之妻财，又逢月内之生气者，占妻必孕也。生气：正月起子，顺行十二。胎财生气：水土日在午、七月；金日在卯、四月；火日在子、正月；木日在酉、十月。"},
	{Number: 20, Title: "胎财死气损胎推", Text: "胎财死气损胎推", Note: "凡胎神作月内之死气，占妇女怀孕主损胎不育。死气：正月起午、顺行十二。胎财死气：水土日在午、正月；金日在卯、十月；火日在子、七月；木日在酉、四月。"},
	{Number: 21, Title: "交车相合交关利", Text: "交车相合交关利", Note: "交车者，交叉也。此视第一课与第三课之交互生克刑害情况。有十等：交车长生、交车财、交车脱、交车害、交车空、交车刑、交车克、交车冲、交车三交、交车合等。"},
	{Number: 22, Title: "上下皆合两心齐", Text: "上下皆合两心齐", Note: "谓支干上神作六合，地盘支干亦作六合。如乙酉、丙申、戊申、辛卯、壬寅五日伏吟是也。日干与上神作六合者，如乙酉日酉加乙；甲申日干上亥。"},
	{Number: 23, Title: "彼求我事支传干", Text: "彼求我事支传干", Note: "谓初传起于支上，末传归于干上者，凡占必主他人委托我干谋事体，凶吉皆成。占吉就吉，占凶就凶。如癸酉日干上酉。"},
	{Number: 24, Title: "我求彼事干传支", Text: "我求彼事干传支", Note: "谓初传从干上起，末传归于支上者，凡事勉强，不免俯求于人，亦为人抑勒，难自屈伸，旺相尤吉，死囚不安。如丁亥日干上酉作初传，支上丑为末传。"},
	{Number: 25, Title: "金日逢丁凶祸动", Text: "金日逢丁凶祸动", Note: "谓庚辛二日，三传年命日辰逢旬内六丁神者，平人必主凶动，喜占人行年上神制丁乘神。如有官人占之，则赴任极速，反不欲行年上神克去六丁乘神。"},
	{Number: 26, Title: "水日逢丁财动之", Text: "水日逢丁财动之", Note: "谓壬癸二日，三传年命日辰逢旬内之丁神者，必主财动，或远方财来，或娶妻之喜、别妻之忧。若有行年上神克去六丁乘神则财不动。"},
	{Number: 27, Title: "传财化鬼财休觅", Text: "传财化鬼财休觅", Note: "谓三传皆作日之财，生起干上日鬼，而伤日干者，必因取财而致祸，或因妻而损财；生起支上鬼者主破家。如辛亥日干上午。"},
	{Number: 28, Title: "传鬼化财钱险危", Text: "传鬼化财钱险危", Note: "三传俱鬼、或三合课虽作日之鬼，而初中二课俱空、独存一字，中间为财者。乃名全鬼变为财。其财终是从险中出，纵得之，亦不安稳。"},
	{Number: 29, Title: "眷属丰盈居狭宅", Text: "眷属丰盈居狭宅", Note: "谓三传生其日干，反脱其支辰是也。值此必人口丰盈而居宅狭窄也。如甲申日干上午。若得此课，乃造化使然，切不可迁居，恐反生灾咎。"},
	{Number: 30, Title: "屋宅宽广致人衰", Text: "屋宅宽广致人衰", Note: "谓三传窃盗日干，反生支辰者是也。凡占必宅不容人住，或人口少而居宽广之宅屋，致使人口日渐衰羸，患难俱生。此则速宜迁居。如甲辰日戌加寅。"},
	{Number: 31, Title: "三传递生人举荐", Text: "三传递生人举荐", Note: "三传递生有二：一者初、中、末递生日干；二者末、中、初递生日干。凡占必有人于上位举荐，如欲干官或请举文状，必能成就。"},
	{Number: 32, Title: "三传互克众人欺", Text: "三传互克众人欺", Note: "三传互克，亦有二等，同上。凡占必有人递相欺凌於我，如被他人围攻状，在位官占此不利。如丙辰日寅加酉。"},
	{Number: 33, Title: "有始无终难变易", Text: "有始无终难变易", Note: "此句有二：有始无终者，乃初传是日之长生，末传为干之墓是也；事之初，如花似锦，后必无成。难变易者，初为干墓，末为干之长生是也，凡事先难後易。"},
	{Number: 34, Title: "苦去甘来乐里悲", Text: "苦去甘来乐里悲", Note: "苦去甘来者，末、中、递生初传而克日干，诚被初传之苦也，殊不知反赖末传之子孙克制初传之鬼也。乐里悲，干支上见鬼克为凶，传见子孙为救无忧。"},
	{Number: 35, Title: "人宅受脱俱招盗", Text: "人宅受脱俱招盗", Note: "此亦有二，一者干支上皆乘脱气，二者干上脱支、支上脱干。凡占，人被脱赚，家宅被盗。遥克、昴星、别责，乘空落空为初传发用，乘玄，必主失盗。"},
	{Number: 36, Title: "干支皆败事倾颓", Text: "干支皆败事倾颓", Note: "谓干支上皆逢败气者，占身气血衰败，占宅屋舍崩颓，日渐狼狈全无长进。若告发他人阴事，必牵连我之旧过，彼此皆值衰败也。如甲申日干上子。"},
	{Number: 37, Title: "末助初兮三等论", Text: "末助初兮三等论", Note: "（1）有末传助其初传而生日干者；（2）有末助初而克日干者。（3）有末助初而作日之财者。末助初克日者，欲年命制末则吉，生末凶。如庚午干上午。"},
	{Number: 38, Title: "闭口卦体两般推", Text: "闭口卦体两般推", Note: "闭口课：(1)旬尾加旬首发用，如甲申日巳加申；(2)旬首乘玄武发用，如丁酉日午加酉；(3)旬首上神乘玄武发用，甲子日辰加子。"},
	{Number: 39, Title: "太阳照武宜擒贼", Text: "太阳照武宜擒贼", Note: "谓玄武坐于太阳月将之上，占贼必败；纵太阳月将乘空坐空尤好，缘太阳无云翳遮掩，益光明也。如辛亥日亥将戌时，干上亥，是日之脱气三传丑卯寅。"},
	{Number: 40, Title: "后合占婚岂用媒", Text: "后合占婚岂用媒", Note: "干为夫、支为妻，凡占婚全看此。若支干上乘天后、六合，必应私情。如更女之行年居干上，男之行年居支上，此必婚前己有私情，何用媒乎?"},
	{Number: 41, Title: "富贵干支逢禄马", Text: "富贵干支逢禄马", Note: "谓干上有支驿马，支上有干禄神者，名真富贵格。有官人占之，加官进爵，富贵双全；常人占之，病讼俱凶，宅移身动。如丙寅日干上申。"},
	{Number: 42, Title: "尊崇传内遇三奇", Text: "尊崇传内遇三奇", Note: "三奇有二：有三传全遇甲戊庚者，有三传全遇乙丙丁者。其取法也有二：有遁旬中之干者，有遁五子。"},
	{Number: 43, Title: "害贵讼直作曲断", Text: "害贵讼直作曲断", Note: "四课三传中见贵人受克或害，如占讼，理虽直而必致曲断，事小而必大凶。余占亦皆弄巧成拙，只宜识时而屑就，庶不为大祸。如甲申日未加申。"},
	{Number: 44, Title: "课传俱贵转无依", Text: "课传俱贵转无依", Note: "此谓四课三传皆是昼夜贵人，名遍地贵人，贵多反不贵。凡占不归其一，反无依倚，托事无成。如丁酉日干上酉。"},
	{Number: 45, Title: "昼夜贵加求两贵", Text: "昼夜贵加求两贵", Note: "此指六处有旦暮天乙相加者。如占告贵求事，必干涉两贵人而成就；如占谒贵，必不得见，盖贵临贵位乃官见官也；如是同官占之，反宜谒见。"},
	{Number: 46, Title: "贵人差迭事参差", Text: "贵人差迭事参差", Note: "谓昼贵临于夜地，夜贵却临旦方，故名贵人差迭。如占告贵事，多不归一。"},
	{Number: 47, Title: "贵虽在狱宜临干", Text: "贵虽在狱宜临干", Note: "天乙贵人加临地盘辰戌上者，虽名入狱，如是乙辛二日，却是贵人临身，反宜干贵成事。其余八干旦暮贵人坐地盘辰戌上，始名天乙入狱。"},
	{Number: 48, Title: "鬼乘天乙乃神祇", Text: "鬼乘天乙乃神祇", Note: "六辛日午加干，旦占，虽是日鬼临身，却是贵人，切勿作鬼祟看之。占病是神祇为患，宜修功德，得无咎。"},
	{Number: 49, Title: "两贵受克难干贵", Text: "两贵受克难干贵", Note: "凡昼夜贵人皆立受克之方者，切不可告贵用事；缘二贵自受克制，必不能成就我也。不论在传不在传皆如是。"},
	{Number: 50, Title: "二贵皆空虚喜期", Text: "二贵皆空虚喜期", Note: "此谓旦暮贵人皆值空亡者，如干投贵人事已蒙许诺，后却被人谗越而不成，凡占不免弄巧成拙。有人报喜，终是虚信。"},
	{Number: 51, Title: "魁度天门关隔定", Text: "魁度天门关隔定", Note: "戌为天魁、亥为天门。凡占戌加亥发用者，谋望作为皆被阻隔。占病多是膈气、食积；占盗贼难获；访人不见。诸占不离关隔二字。"},
	{Number: 52, Title: "罡塞鬼户任谋为", Text: "罡塞鬼户任谋为", Note: "辰为天罡、寅为鬼户，凡辰加寅为罡塞鬼户。不论在传不在传皆是罡塞鬼户，众鬼不能窥觑也。贵登天门、罡塞鬼户，凡占无不亨利。"},
	{Number: 53, Title: "两蛇夹墓凶难免", Text: "两蛇夹墓凶难免", Note: "独有丙戌日(戌加巳)，支辰来墓日干，并旦暮天将皆乘蛇，地盘之巳亦是螣蛇之位，故名两蛇夹墓。占病腹中必有积块，以致不救。"},
	{Number: 54, Title: "虎视逢虎力难施", Text: "虎视逢虎力难施", Note: "旧注谓此虎视课乃柔日；《课经》则将昴星课分为：刚日虎视转蓬、柔日为冬蛇掩目。此为虎视课而上乘白虎者，如戊寅日干上酉。"},
	{Number: 55, Title: "所谋多拙逢网罗", Text: "所谋多拙逢网罗", Note: "此指干上乘干前一辰，支上乘支前一辰，名天罗地网。凡得此卦，如罗网缠裹身宅，诸占岂能亨快。进连茹课中多有，如甲申日干上卯。"},
	{Number: 56, Title: "天网自裹己招非", Text: "天网自裹己招非", Note: "如甲申日未加寅，乃墓神覆日；如占人本命又是未生，乃名天网自裹。凡占必是自招其祸，非干他人。"},
	{Number: 57, Title: "费有余而得不足", Text: "费有余而得不足", Note: "谓支干逢生，却是空亡，此为见生不生、不如无生；进而寻三传之财，又是空陷或为破碎。凡占得之不足、费之有余。"},
	{Number: 58, Title: "用破身心无所归", Text: "用破身心无所归", Note: "财禄俱作鬼空，无实得之意也。(1)初传虽是日财，奈坐克乘虎，又引入中末鬼乡。(2)初传财，却被两蛇夹克，中末空陷。(3)财被夹克、中末鬼空或传墓入墓。(4)干上空财，中脱末空。"},
	{Number: 59, Title: "华盖覆日人昏晦", Text: "华盖覆日人昏晦", Note: "谓支辰之华盖作干之墓神，临于干上发用者是也。凡占身位，多昏多晦，座难明白；或遭冤枉，难分诉；占行人不归，尽在彼处不如意也。"},
	{Number: 60, Title: "太阳射宅屋光辉", Text: "太阳射宅屋光辉", Note: "此支墓临支，又适为月将，返名太阳辉照家宅，其屋必向阳而明，不然常有上人光顾；如太岁贵人、入宅多美。"},
	{Number: 61, Title: "干乘墓虎无占病", Text: "干乘墓虎无占病", Note: "此惟六辛日，丑加戌，旦将乘白虎作墓神。内辛酉日丑作空墓，辛巳日丑作丁神乘虎作墓，尤可畏也，占病必死，且宜堤防仇人。"},
	{Number: 62, Title: "支乘墓虎有伏尸", Text: "支乘墓虎有伏尸", Note: "干墓临支，或支墓临支，占宅必有伏尸为祸，又以克宅者为的。如乙亥日未加亥，是干墓临支，旦乘白虎。"},
	{Number: 63, Title: "彼此全伤防两损", Text: "彼此全伤防两损", Note: "支干各被上神所克者，故名。诸占必两边各有所亏，占讼两败，占身被伤，占宅崩损。如丁亥日干上子。"},
	{Number: 64, Title: "夫妇芜淫各有私", Text: "夫妇芜淫各有私", Note: "干被支上神克，支又被干上神克者，为芜淫卦。夫妇既无好合之情，必各有奸私不协之意。"},
	{Number: 65, Title: "干墓并关人宅废", Text: "干墓并关人宅废", Note: "日干之墓，作四季之关神发用者是。关神者春丑夏辰秋未冬戌。如在日干两课上发用者主人衰，在支辰两课上发用者主宅废。"},
	{Number: 66, Title: "支坟财并旅程稽", Text: "支坟财并旅程稽", Note: "地支之墓却作日干之财者，凡谋蹇滞不亨通也。必主贩商折本，在路阻程，如甲子日辰加子。"},
	{Number: 67, Title: "受虎克神为病症", Text: "受虎克神为病症", Note: "白虎乘神所克者即受病之处也，如虎乘金神是肝受病，当治肺不可治肝，余可类推。虎乘丁鬼格，六辛日，有虎乘丁，克处必痛。"},
	{Number: 68, Title: "制鬼之位乃良医", Text: "制鬼之位乃良医", Note: "凡日鬼临于六处，鬼克者即病，如火鬼即肺病、水鬼即心病。制鬼之处，即良医所在。"},
	{Number: 69, Title: "虎乘遁鬼殃非浅", Text: "虎乘遁鬼殃非浅", Note: "白虎加临旬内之遁干，适为日鬼者，凡占为殃非浅，其咎弥深，纵空亡亦不能救。"},
	{Number: 70, Title: "鬼临三四讼灾随", Text: "鬼临三四讼灾随", Note: "日干之鬼，临于第三、四课全者，官司病患，继踵而至；惟宜修德作福，庶得稍轻，亦未免病讼二事。"},
	{Number: 71, Title: "病符克宅全家患", Text: "病符克宅全家患", Note: "病符者，旧太岁是也。若病符临支又克支者，主全家病患，更乘天鬼，必是时疫。病符乘白虎临支克支尤凶。"},
	{Number: 72, Title: "丧吊全逢挂缟衣", Text: "丧吊全逢挂缟衣", Note: "岁前二辰为丧门，岁后二辰为吊客。如支干上丧吊全逢，主凶。又占者年命上乘之，其年有孝服。"},
	{Number: 73, Title: "前后逼迫难进退", Text: "前后逼迫难进退", Note: "此谓进则于三传上皆空，退于支干上又是鬼脱，乃前不可进、後不可退，切不可谋动，否则虚耗百出。"},
	{Number: 74, Title: "空空如也事休追", Text: "空空如也事休追", Note: "谓三传皆空亡是也，于进连茹课中多有。三合课中两传空亡，只有一传不空，而上乘天空者，亦是此例。凡占皆指空画空，全无实迹。"},
	{Number: 75, Title: "宾主不投刑在上", Text: "宾主不投刑在上", Note: "凡支干上乘有三刑者，凡占未免有相刑之意，所谋交涉之事，必各有异心。一字刑即自刑；二字刑即支干上乘子卯；三字刑即三传寅巳申、丑戌未也。"},
	{Number: 76, Title: "彼此猜忌害相随", Text: "彼此猜忌害相随", Note: "此例有五：(1)干支上下皆各作六害；(2)支干上神作六害；(3)支干天地盘皆作六害；(4)支干三传作六害；(5)支干上下交互作六害。"},
	{Number: 77, Title: "互生俱生凡事益", Text: "互生俱生凡事益", Note: "互生者，干上神生支、支上神生干是也，如辛卯日干上亥。俱生者，干上神生干、支上神生支是也，如丙寅丁酉日干上寅。"},
	{Number: 78, Title: "互旺皆旺坐谋宜", Text: "互旺皆旺坐谋宜", Note: "互旺者，干上乃支之旺神，支上乃干之旺神，如甲申日干上酉。皆旺者，干上乘干之旺神，支上乘支之旺神，如甲申日干上卯。"},
	{Number: 79, Title: "干支值绝凡谋决", Text: "干支值绝凡谋决", Note: "支干上皆乘绝神。绝神作鬼，只宜结绝凶事，亦宜释解官讼，占病痊。绝神作日之财，只宜结绝财物事，不利占妻病。"},
	{Number: 80, Title: "人宅皆死各衰羸", Text: "人宅皆死各衰羸", Note: "死气：金日子，木日午，水土日卯，火日酉。干支上互乘死气者，即干上是支之死气、支上是干之死气者。有支干全乘死气者，此万事不宜动谋。"},
	{Number: 81, Title: "传墓入墓分憎爱", Text: "传墓入墓分憎爱", Note: "初传发用，为中传所墓，末传又入墓乡，为传墓入墓。须视初传是何类神言之，是财神、禄神、长生、官星不宜入墓；如是鬼、脱等凶星，却喜中末之墓也。"},
	{Number: 82, Title: "不行传者考初时", Text: "不行传者考初时", Note: "不行传，谓初实而中末空亡是也。中末既空，只以初传断其吉凶，言其事类。"},
	{Number: 83, Title: "万事喜忻三六合", Text: "万事喜忻三六合", Note: "此谓三合课中，于干上或支上又见一字，与三合之中间一字作六合者。如三传寅午戌，在干上或支上又见未者是。三六相呼见喜忻，纵然带恶不成嗔。"},
	{Number: 84, Title: "合中犯杀蜜中砒", Text: "合中犯杀蜜中砒", Note: "三合课中，干支上有一神与三合中一字作刑、害、冲者名合中犯煞。如三传寅午戌，干支上见午刑、丑害、子冲。惟防好里相欺，笑里藏刀。"},
	{Number: 85, Title: "初遭夹克不由己", Text: "初遭夹克不由己", Note: "初传坐于克方，又被天将所伤，故名夹克。凡占身不由己，受人驱策。"},
	{Number: 86, Title: "将逢内战所谋危", Text: "将逢内战所谋危", Note: "谓方克神、神克将为内战。如六合内战为发用者，主事将成而被人搅扰。天后内战为发用者，必妻常不满而多病。"},
	{Number: 87, Title: "人宅坐墓甘招晦", Text: "人宅坐墓甘招晦", Note: "墓者，昧没之神。天盘支干皆坐于地盘墓上者，乃心肯意肯，情愿受其暗昧。凡事自招其祸，切不可怨天尤人。"},
	{Number: 88, Title: "干支乘墓各昏迷", Text: "干支乘墓各昏迷", Note: "支干全被上神所墓者，其人如云雾中行，其家宅蔽而自尘。经云：墓覆日辰，人宅昏沉。"},
	{Number: 89, Title: "任信丁马须言动", Text: "任信丁马须言动", Note: "任信者，伏吟课也，刚日名自任，柔日名自信。凡三传及支干、年命上有旬内之丁神，或乘天马驿马者，必静而求动；年命上乘魁罡主动尤速。"},
	{Number: 90, Title: "来去俱空岂动宜", Text: "来去俱空岂动宜", Note: "来去者，返吟卦也。缘初传与末传，初中末往来交互也。返吟主动，但三传皆空亡者，虽有动意而实不动也。"},
	{Number: 91, Title: "虎临干鬼凶速速", Text: "虎临干鬼凶速速", Note: "日干之鬼，上乘白虎者，凡占凶祸速中又速。如六己日卯加未夜，此虎鬼临干者。"},
	{Number: 92, Title: "龙加生气吉迟迟", Text: "龙加生气吉迟迟", Note: "青龙乘生干之神，又作月内之生气者，虽目下未足峥嵘，却徐徐而发福也。"},
	{Number: 93, Title: "妄用三传灾福异", Text: "妄用三传灾福异", Note: "壬课关键在于三传，若三传有错误，吉凶灾福应无的验。尤以涉害、择比之中差异甚大，研习者应当注意。"},
	{Number: 94, Title: "喜惧空亡乃妙机", Text: "喜惧空亡乃妙机", Note: "凡空亡，有要见、不要见之分。其天盘作空亡者为游行空亡，其吉凶有七八分；在地盘作空亡者，为落底空亡，其吉凶十分。凶神宜空，吉神不宜空。"},
	{Number: 95, Title: "六爻现卦防其克", Text: "六爻现卦防其克", Note: "财爻现卦忧父母，父母现卦忧子孙，子孙现卦忧官事，官鬼现卦忧兄弟与己身，同类现卦忧妻财。"},
	{Number: 96, Title: "旬内空亡逐类推", Text: "旬内空亡逐类推", Note: "如甲子旬中空戌亥，甲子乙丑空妻财父母，丙寅丁卯空官鬼暮贵，戊辰己巳空兄弟妻财，庚午辛未空父母子息，壬申癸酉空官鬼兄弟，壬日禄空。"},
	{Number: 97, Title: "所筮不入仍凭类", Text: "所筮不入仍凭类", Note: "如占失脱，虽玄武并脱气日鬼不在六处，亦宣用此类而言其方所、色目也。其余所占，皆如其法也。"},
	{Number: 98, Title: "非占现类勿言之", Text: "非占现类勿言之", Note: "前贤有诸秘法，用之极验，如白虎临寅在支发用，必宅中有屋梁摧折之惊；但占者问求财，虽得此课，切不可言其屋梁摧折也。"},
	{Number: 99, Title: "常问不应逢吉象", Text: "常问不应逢吉象", Note: "诸龙德、铸印、高盏乘轩、斫轮、官爵等吉泰卦，有官人占之，迁官转职；若寻常百姓，既不趋事贵人，又无官禄，见官贵何来。"},
	{Number: 100, Title: "已灾凶逃返无疑", Text: "已灾凶逃返无疑", Note: "凡值丧魂、魄化、天祸、天寇、伏殃、天狱、天网四张、天地二烦诸凶卦，如在已见病讼灾迪之後占得，其灾却有消除之意，反不足为虑也。"},
}
